subLevels.cadence:
# ── Tcl Scripting in Cadence Innovus ───────────────────

# Variable assignment
set design_name "my_soc"
set clk_period  10.0
puts "Design: $design_name, Clock: ${clk_period}ns"

# Loop over multiple corners
foreach corner {ss_0p9v_125c tt_1p0v_25c ff_1p1v_m40c} {
  report_timing -view $corner -max_paths 5
}

# Procedure: report and save
proc run_and_save {stage} {
  report_timing -max_paths 10
  report_area
  saveDesign ./checkpoints/${stage}.enc
  puts "Stage $stage complete"
}

# Conditional check
set slack [get_db [get_timing_paths] .slack]
if { $slack < 0 } {
  puts "ERROR: Timing violation! Slack = $slack"
} else {
  puts "Timing clean. Slack = $slack"
}

# Get all clocks and print periods
foreach_in_collection clk [all_clocks] {
  puts "Clock: [get_db $clk .name] Period: [get_db $clk .period]"
}

subLevels.synopsys:
# ── Tcl Scripting in Synopsys Fusion Compiler ───────────

# Variable assignment
set design_name "my_soc"
set clk_period  10.0
puts "Design: $design_name, Clock: ${clk_period}ns"

# Loop over scenarios
foreach_in_collection scenario [all_scenarios] {
  set name [get_object_name $scenario]
  report_timing -scenario $name -max_paths 5
}

# Procedure: run stage and save
proc run_stage {stage_name} {
  report_timing
  report_area
  save_block -as ./checkpoints/$stage_name
  puts "$stage_name complete"
}

# Conditional check
set wns [get_attribute [get_timing_paths -max_paths 1] slack]
if { $wns < 0 } {
  puts "ERROR: WNS = $wns — timing violation"
} else {
  puts "WNS = $wns — timing clean"
}

# Get all clocks
foreach_in_collection clk [all_clocks] {
  puts "Clock: [get_attribute $clk name]"
  puts "Period: [get_attribute $clk period]"
}

